import { useState } from 'react';
import './App.css';

function App() {


  const [name,setName]=useState("")
  const [age,setAge]=useState("")
  const [phone,setPhone]=useState('')
  const[check,setCheck]=useState(false)
  const [slary,setSalry]=useState("")


  function handleSubmit(){
    if(name.trim() !== "" & phone.length < 10 || phone.length > 15 & 80 < age <18  )
      return alert("Sucsses")
    else
      return alert("error")

  }
  return (
    <div className="App">
      <div className='form'>


        <h2>Request loan for <span>HSBC</span> bank</h2>

        <input type='text' placeholder='Enter Your Name' 
        onChange={(e)=>setName(e.target.value)}></input><br/>

        <input type='text' placeholder='Enter Your Phone Number'
        onChange={(e)=>setPhone(e.target.value)}></input><br/>

        <input type='text' placeholder='Enter Your Age'
        onChange={(e)=>setAge(e.target.value)}></input><br/>

      <div className='check'>
        <input type='checkbox'/>
        <label> Aye You have employee?</label>
      </div>

        <select>
          <option> Select Salary </option>
          <option>Less than 15,000k</option>
          <option>15,000 to 35,000k</option>
          <option>More than 35,000k</option>
        </select><br/>

        <button type='submit' onClick={handleSubmit}>Submit</button>


      </div>
            </div>

  );
}

export default App;
